                  duration: 授予触发条件 === '随下次行动触发' ? 1 : Math.max(1, Number(directGrantEffect.持续回合 || directGrantEffect.持续 || 1)),
                  来源技能: playerAction.skill?.name || playerAction.skill?.魂技名 || '',
