            if (NPC临时技能效果.length || NPC授予前置效果.length) {
              NPC临时技能已生效 = 执行临时行动直接效果(defender, attacker, npcAction, [...NPC临时技能效果, ...NPC授予前置效果]) || NPC临时技能已生效;
            }
