                  lock_level: isBuff ? 0 : (scaledCalc?.lock_level ?? 0),
                  skip_turn: scaledCalc?.skip_turn ?? false,
                  cannot_react: scaledCalc?.cannot_react ?? false,
                  dot_damage: scaledCalc?.dot_damage ?? pState.持续真伤dot,
